CREATE TABLE satelites (
  id SERIAL PRIMARY KEY,
  codigo TEXT UNIQUE,
  status TEXT DEFAULT 'Ativo'
);

CREATE TABLE produtos (
  id SERIAL PRIMARY KEY,
  nome TEXT NOT NULL,
  preco NUMERIC CHECK (preco > 0)
);

CREATE TABLE naves (
  id SERIAL PRIMARY KEY,
  nome TEXT,
  planeta_id INT REFERENCES planetas(id)
);
